#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int prev, cur;
        long long ans = 0;
        if (N>0) {
            scanf("%d", &prev);
            ans = 1;
            for (int i=1;i<N;i++) {
                scanf("%d", &cur);
                if (cur != prev) ans++;
                prev = cur;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

