const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  if (N === 0) { outputs.push('0'); continue; }
  let prev = Number(input[idx++]);
  let ans = 1;
  for (let i = 1; i < N; i++) {
    const cur = Number(input[idx++]);
    if (cur !== prev) ans++;
    prev = cur;
  }
  outputs.push(String(ans));
}
console.log(outputs.join('\n'));
